/// Extract block_type field from FAR value (bits [25:23]).
pub fn farBlockType(far: u32) u3 {
    return @intCast((far >> 23) & 0x7);
}

/// Extract top/bottom half field from FAR value (bit [22]).
pub fn farHalf(far: u32) u1 {
    return @intCast((far >> 22) & 0x1);
}

/// Extract row field from FAR value (bits [21:17]).
pub fn farRow(far: u32) u5 {
    return @intCast((far >> 17) & 0x1F);
}

